#include<bits/stdc++.h>
using namespace std;
int a[1010],f[1010][1010],g[1010][1010],s[1010];
int main()
{
    int n;
    scanf("%d",&n);
    memset(g,0x3f,sizeof(g));
    memset(f,-0x3f,sizeof(f));
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        a[i+n]=a[i];
        f[i][i]=g[i][i]=f[i+n][i+n]=g[i+n][i+n]=0;
        s[i]=s[i-1]+a[i];
    }
    for(int i=n+1;i<=n*2;i++)
    {
        s[i]=s[i-1]+a[i];
    }
    for(int len=1;len<=n;len++)
    {
        for(int l=1,r=len;r<=n*2;l++,r++)
        {
            for(int k=l;k<r;k++)
            {
                f[l][r]=max(f[l][r],f[l][k]+f[k+1][r]+s[r]-s[l-1]);
                g[l][r]=min(g[l][r],g[l][k]+g[k+1][r]+s[r]-s[l-1]);
            }
        }
    }
    int ans1=INT_MAX,ans2=0;
    for(int i=1;i<=n;i++)
    {
        ans1=min(ans1,g[i][i+n-1]);
        ans2=max(ans2,f[i][i+n-1]);
    }
    printf("%d\n%d",ans1,ans2);
    return 0;
}
